export const commitCounterRegistry = createAsyncThunk<
  CounterRegistryPayload,
  CommitCounterRegistryArgs,
  { rejectValue: CounterRegistryError }
>('counterRegistry/commit', async ({ counterId, metrics, status, notes }, { rejectWithValue }) => {
  try {
    const response = await axiosInstance.post<CounterRegistryPayload>(
      `/counters/${counterId}/commit?format=registry`,
      {
        ...(metrics ? { metrics } : {}),
        ...(status ? { status } : {}),
        ...(notes !== undefined ? { notes } : {}),
      },
      withCredentialsConfig,
    );
    return response.data;
  } catch (error) {
    return rejectWithValue(buildRejectValue(error, 'Failed to commit counter changes'));
  }
});

export const finalizeCounterReservations = createAsyncThunk<
  CounterRegistryPayload,
  FinalizeCounterReservationsArgs,
  { rejectValue: CounterRegistryError }
>(
  'counterRegistry/finalizeReservations',
  async ({ counterId, attendanceUpdates, metrics, status, notes }, { rejectWithValue }) => {
    try {
      const response = await axiosInstance.post<CounterRegistryPayload>(
        `/counters/${counterId}/finalize-reservations?format=registry`,
        {
          ...(attendanceUpdates && attendanceUpdates.length > 0 ? { attendanceUpdates } : {}),
          ...(metrics ? { metrics } : {}),
          ...(status ? { status } : {}),
          ...(notes !== undefined ? { notes } : {}),
        },
        withCredentialsConfig,
      );
      return response.data;
    } catch (error) {
      return rejectWithValue(buildRejectValue(error, 'Failed to finalize reservations'));
    }
  },
);

export const flushDirtyMetrics = createAsyncThunk<
  FlushMetricsResult,
  void,
  { state: RootState; rejectValue: string }
>('counterRegistry/flushDirtyMetrics', async (_, { getState, rejectWithValue }) => {
  const state = getState().counterRegistry;
  const counterId = state.counter?.counter.id;
  if (!counterId) {
    return {
      metrics: state.counter?.metrics ?? [],
      derivedSummary: state.summary ?? null,
    };
  }

  if (state.dirtyMetricKeys.length === 0) {
    return {
      metrics: state.counter?.metrics ?? [],
      derivedSummary: state.summary ?? null,
    };
  }

  const rows = state.dirtyMetricKeys
    .map((key) => state.metricsByKey[key])
    .filter((metric): metric is MetricCell => Boolean(metric))
    .filter((metric) => {
      const key = buildMetricKey(metric);
      const persisted = state.persistedMetricsByKey[key];
      const nextQty = Math.max(0, Number(metric.qty) || 0);
      if (persisted) {
        const persistedQty = Math.max(0, Number(persisted.qty) || 0);
        return nextQty !== persistedQty;
      }
      return nextQty > 0;
    })
    .map((metric) => {
      const nextQty = Math.max(0, Number(metric.qty) || 0);
      return {
        channelId: metric.channelId,
        kind: metric.kind,
        addonId: metric.addonId,
        tallyType: metric.tallyType,
        period: metric.period,
        qty: nextQty,
      } satisfies {
        channelId: number;
        kind: MetricKind;
        addonId: number | null;
        tallyType: MetricTallyType;
        period: MetricPeriod;
        qty: number;
      };
    });

  if (rows.length === 0) {
    return {
      metrics: state.counter?.metrics ?? [],
      derivedSummary: state.summary ?? null,
    };
  }

  try {
    const response = await axiosInstance.put<FlushMetricsResult>(
      `/counters/${counterId}/metrics?format=registry`,
      rows,
      withCredentialsConfig,
    );
    return {
      metrics: response.data.metrics.map(normalizeMetric),
      derivedSummary: response.data.derivedSummary,
    };
  } catch (error) {
    if (error instanceof Error) {
      return rejectWithValue(error.message);
    }
    return rejectWithValue('Failed to save counter metrics');
  }
});

const counterRegistrySlice = createSlice({
  name: 'counterRegistry',
  initialState,
  reducers: {
    clearCounter: (state) => {
      state.counter = null;
      state.channels = [];
      state.addons = [];
      state.summary = null;
      state.metricsByKey = {};
      state.dirtyMetricKeys = [];
      state.error = null;
    },
    clearDirtyMetrics: (state) => {
      state.metricsByKey = {};
      state.dirtyMetricKeys = [];
    },
    setMetric: (state, action: PayloadAction<MetricCell>) => {
      const metric = normalizeMetric(action.payload);
      const key = buildMetricKey(metric);
      const persisted = state.persistedMetricsByKey[key];
      if (!persisted && metric.qty === 0) {
        state.metricsByKey[key] = metric;
        if (!state.dirtyMetricKeys.includes(key)) {
          state.dirtyMetricKeys.push(key);
        }
      } else {
      state.metricsByKey[key] = metric;
      if (!state.dirtyMetricKeys.includes(key)) {
        state.dirtyMetricKeys.push(key);
      }
      }

      if (state.counter) {
        const existingIndex = state.counter.metrics.findIndex(
          (existing) => buildMetricKey(existing) === key,
        );
        if (existingIndex >= 0) {
          state.counter.metrics[existingIndex] = metric;
        } else {
          state.counter.metrics.push(metric);
        }
      }
    },
  },
  extraReducers: (builder) => {
    builder
      .addCase(ensureCounterForDate.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(ensureCounterForDate.fulfilled, (state, action) => {
        state.loading = false;
        ingestPayload(state, action.payload);
      })
      .addCase(ensureCounterForDate.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload?.message ?? action.error.message ?? 'Failed to ensure counter';
      })
      .addCase(submitCounterSetup.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(submitCounterSetup.fulfilled, (state, action) => {
        state.loading = false;
        ingestPayload(state, action.payload);
      })
      .addCase(submitCounterSetup.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload?.message ?? action.error.message ?? 'Failed to submit counter setup';
      })
      .addCase(fetchCounterByDate.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(fetchCounterByDate.fulfilled, (state, action) => {
        state.loading = false;
        ingestPayload(state, action.payload);
      })
      .addCase(fetchCounterByDate.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload?.message ?? action.error.message ?? 'Failed to load counter';
      })
      .addCase(fetchCounterById.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(fetchCounterById.fulfilled, (state, action) => {
        state.loading = false;
        ingestPayload(state, action.payload);
      })
      .addCase(fetchCounterById.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload?.message ?? action.error.message ?? 'Failed to load counter';
      })
      .addCase(updateCounterProduct.pending, (state) => {
        state.savingProduct = true;
        state.error = null;
      })
      .addCase(updateCounterProduct.fulfilled, (state, action) => {
        state.savingProduct = false;
        ingestPayload(state, action.payload);
      })
      .addCase(updateCounterProduct.rejected, (state, action) => {
        state.savingProduct = false;
        state.error = action.payload?.message ?? action.error.message ?? 'Failed to update product';
      })
      .addCase(updateCounterManager.pending, (state) => {
        state.loading = true;
      })
      .addCase(updateCounterManager.fulfilled, (state, action) => {
        state.loading = false;
        ingestPayload(state, action.payload);
      })
      .addCase(updateCounterManager.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload?.message ?? action.error.message ?? 'Failed to update manager';
      })
      .addCase(updateCounterStatus.pending, (state) => {
        state.savingStatus = true;
      })
      .addCase(updateCounterStatus.fulfilled, (state, action) => {
        state.savingStatus = false;
        ingestPayload(state, action.payload);
      })
      .addCase(updateCounterStatus.rejected, (state, action) => {
        state.savingStatus = false;
        state.error = action.payload?.message ?? action.error.message ?? 'Failed to update status';
      })
      .addCase(updateCounterNotes.pending, (state) => {
        state.savingNotes = true;
      })
      .addCase(updateCounterNotes.fulfilled, (state, action) => {
        state.savingNotes = false;
        ingestPayload(state, action.payload);
      })
      .addCase(updateCounterNotes.rejected, (state, action) => {
        state.savingNotes = false;
        state.error = action.payload?.message ?? action.error.message ?? 'Failed to update notes';
      })
      .addCase(updateCounterStaff.pending, (state) => {
        state.savingStaff = true;
      })
      .addCase(updateCounterStaff.fulfilled, (state, action) => {
        state.savingStaff = false;
        ingestPayload(state, action.payload);
      })
      .addCase(updateCounterStaff.rejected, (state, action) => {
        state.savingStaff = false;
        state.error = action.payload?.message ?? action.error.message ?? 'Failed to update staff';
      })
      .addCase(commitCounterRegistry.pending, (state) => {
        state.savingMetrics = true;
        state.error = null;
      })
      .addCase(commitCounterRegistry.fulfilled, (state, action) => {
        state.savingMetrics = false;
        ingestPayload(state, action.payload);
      })
      .addCase(commitCounterRegistry.rejected, (state, action) => {
        state.savingMetrics = false;
        state.error = action.payload?.message ?? action.error.message ?? 'Failed to save counter';
      })
      .addCase(finalizeCounterReservations.pending, (state) => {
        state.savingMetrics = true;
        state.error = null;
      })
      .addCase(finalizeCounterReservations.fulfilled, (state, action) => {
        state.savingMetrics = false;
        ingestPayload(state, action.payload);
      })
      .addCase(finalizeCounterReservations.rejected, (state, action) => {
        state.savingMetrics = false;
        state.error = action.payload?.message ?? action.error.message ?? 'Failed to finalize reservations';
      })
      .addCase(flushDirtyMetrics.pending, (state) => {
        state.savingMetrics = true;
      })
      .addCase(flushDirtyMetrics.fulfilled, (state, action) => {
        state.savingMetrics = false;
        const payload = action.payload;
        if (state.counter) {
          state.counter.metrics = payload.metrics.map(normalizeMetric);
        }
        state.summary = payload.derivedSummary;
        state.metricsByKey = {};
        state.persistedMetricsByKey = {};
        payload.metrics.forEach((metric) => {
          const normalized = normalizeMetric(metric);
          if (normalized.id != null) {
            state.persistedMetricsByKey[buildMetricKey(normalized)] = normalized;
          } else {
            delete state.persistedMetricsByKey[buildMetricKey(normalized)];
          }
        });
        state.dirtyMetricKeys = [];
      })
      .addCase(flushDirtyMetrics.rejected, (state, action) => {
        state.savingMetrics = false;
        state.error = action.payload ?? action.error.message ?? 'Failed to save metrics';
      });
  },
});

export const { clearCounter, clearDirtyMetrics, setMetric } = counterRegistrySlice.actions;

export const selectCounterRegistry = (state: RootState) => state.counterRegistry;

export default counterRegistrySlice.reducer;






